// Integers
let integer = 42;
console.log(integer);

// Floating point numbers
let float = 3.14159;
console.log(float);
let x = .123;
console.log(x);

// Strings
let string = "Hello World";
console.log(string);

// Booleans
let trueValue = true;
let falseValue = false;
console.log(trueValue);
console.log(falseValue);

// Null
let nullValue = null;
console.log(nullValue);

// Arrays
let array = [1, 2, 3, "hello", true];
console.log(array[0]);
console.log(array[3]);
console.log(array[4]);

// Objects
let obj = {
  name: "Alice",
  age: 25,
  active: true
};
console.log(obj.name);
console.log(obj.age);
console.log(obj.active);
